import type { ScenarioQuestion } from "./types";
type D = "beginner" | "intermediate" | "advanced";
function q(id: string, g: string, s: string, sc: string, qu: string, a: string, f: string, d: D): ScenarioQuestion {
  return { id, formatType: "scenario", categoryGroup: g, subcategory: s, scenarioPrompt: sc, question: qu, exampleAnswer: a, feedback: f, difficulty: d };
}
const ip = "interview_preparation", ws = "workplace_scenarios", ct = "clinical_transition", pd = "professional_development", cn = "career_navigation";

export const bulkGeneratedBatch11: ScenarioQuestion[] = [
  q("sq-bg11-1",ip,"clinical_judgment","A patient on warfarin eats a large amount of leafy greens.","How does vitamin K affect warfarin therapy?","Vitamin K is the antidote to warfarin. Eating large amounts of vitamin K-rich foods counteracts warfarin, lowering INR and increasing clot risk. I would educate patients to maintain consistent vitamin K intake rather than eliminating it. I would check INR and notify the provider for potential dose adjustment.","Warfarin-vitamin K interaction education.","beginner"),
  q("sq-bg11-2",ip,"clinical_judgment","A patient on metformin is scheduled for a contrast CT.","Why must metformin be held for contrast studies?","Metformin combined with IV contrast increases lactic acidosis risk, especially with impaired renal function. I would hold metformin 48 hours before and after the procedure, ensure adequate hydration, monitor renal function post-procedure, and restart metformin only after confirming creatinine is at baseline.","Metformin-contrast safety protocol.","intermediate"),
  q("sq-bg11-3",ip,"clinical_judgment","A patient develops digoxin toxicity.","How would you recognize digoxin toxicity?","Digoxin toxicity presents with nausea, visual changes (yellow-green halos), bradycardia, and potentially fatal arrhythmias. I would check digoxin level (therapeutic 0.8-2.0), potassium (hypokalemia potentiates toxicity), hold the next dose, administer digoxin immune fab for severe toxicity, and place on continuous cardiac monitoring.","Digoxin toxicity recognition with potassium correlation.","intermediate"),
  q("sq-bg11-4",ip,"clinical_judgment","A patient on phenytoin has a level of 25 mcg/mL.","What does a supratherapeutic phenytoin level indicate?","Phenytoin of 25 (therapeutic 10-20) causes nystagmus, ataxia, and slurred speech at mild toxicity. Severe toxicity causes confusion, seizures paradoxically, and cardiac arrhythmias. I would hold the dose, monitor neurological status, check free phenytoin level, assess for contributing factors (drug interactions, liver disease), and notify the provider.","Phenytoin toxicity with zero-order kinetics awareness.","intermediate"),
  q("sq-bg11-5",ip,"clinical_judgment","A patient develops syndrome of inappropriate antidiuretic hormone.","How would you manage SIADH?","SIADH causes water retention leading to dilutional hyponatremia with concentrated urine and low serum osmolality. I would restrict fluids to 800-1000 mL/day, administer demeclocycline or vasopressin receptor antagonists if ordered, monitor sodium correction rate carefully, and identify the underlying cause (malignancy, medications, CNS disorders).","SIADH fluid restriction management.","intermediate"),
  q("sq-bg11-6",ip,"clinical_judgment","A patient develops hypertensive urgency with SBP of 200.","How does urgency differ from emergency in hypertension?","Hypertensive urgency is severely elevated BP without acute end-organ damage. Unlike emergency, it can be treated with oral medications over 24-48 hours. I would not reduce BP too rapidly—target 25% reduction in the first 24 hours. I would assess for end-organ damage (neurological changes, chest pain, vision changes) to distinguish urgency from emergency.","Urgency versus emergency BP management distinction.","intermediate"),
  q("sq-bg11-7",ip,"clinical_judgment","A patient with atrial fibrillation has a CHA2DS2-VASc score of 4.","What does a CHA2DS2-VASc score indicate?","CHA2DS2-VASc estimates stroke risk in atrial fibrillation. A score of 4 indicates high stroke risk requiring anticoagulation. The scoring includes CHF, HTN, Age, Diabetes, prior Stroke/TIA, Vascular disease, Age 65-74, and Sex category. I would ensure the patient is on appropriate anticoagulation and understands the importance of compliance.","CHA2DS2-VASc stroke risk stratification.","intermediate"),
  q("sq-bg11-8",ip,"clinical_judgment","A post-operative patient develops ileus.","How would you manage post-operative ileus?","Post-operative ileus presents with absent bowel sounds, abdominal distension, nausea, and no flatus. I would keep NPO, insert or maintain NG tube for decompression, ensure electrolyte correction (especially potassium and magnesium), encourage ambulation when safe, discontinue opioids if possible, and monitor for resolution with return of bowel sounds and flatus.","Post-operative ileus conservative management.","beginner"),
  q("sq-bg11-9",ip,"clinical_judgment","A patient develops acute gout in their first metatarsal joint.","How would you manage an acute gout attack?","Acute gout presents with severely painful, red, swollen joint—typically the first MTP joint (podagra). I would administer anti-inflammatory medication (NSAIDs, colchicine, or corticosteroids), apply ice, elevate the affected joint, avoid allopurinol initiation during acute attack (can worsen symptoms), and educate about dietary triggers and hydration.","Acute gout management with allopurinol timing.","beginner"),
  q("sq-bg11-10",ip,"clinical_judgment","A patient with ESRD misses dialysis and presents with fluid overload.","How would you manage fluid overload from missed dialysis?","I would assess respiratory status, administer oxygen, position upright, prepare for emergent dialysis, check potassium (hyperkalemia is life-threatening), place on cardiac monitoring, and restrict fluids. If respiratory distress is severe, BiPAP or intubation may be needed as bridge therapy until dialysis can be initiated.","Missed dialysis fluid overload emergency.","intermediate"),
  q("sq-bg11-11",ip,"behavioral","You are asked about your approach to documentation.","How do you approach clinical documentation?","I believe documentation should tell the patient's clinical story clearly enough that any reader could understand what happened, what I observed, what I did, and why. I document in real-time, use objective language, include both normal and abnormal findings relevant to the patient's condition, and ensure my documentation supports continuity of care.","Documentation as clinical storytelling.","beginner"),
  q("sq-bg11-12",ip,"behavioral","You are asked about handling ethical dilemmas.","How do you approach ethical challenges in nursing?","I approach ethical dilemmas by identifying the core ethical principles involved—autonomy, beneficence, non-maleficence, and justice. I gather all relevant information, consider multiple perspectives, consult with the ethics committee when needed, and advocate for the patient's wishes. I recognize that ethical dilemmas rarely have perfect solutions.","Principle-based ethical decision-making.","intermediate"),
  q("sq-bg11-13",ip,"scenario_responses","A patient asks why they need to wear a hospital gown.","How would you explain hospital gown requirements?","The gown provides easy access for clinical assessments, procedures, and emergency care. I understand it is not the most comfortable clothing. If your condition permits, you are welcome to wear your own comfortable clothing during parts of the day. Let me check with your care team about any specific access needs that might affect what you can wear.","Gown rationale with comfort accommodation.","beginner"),
  q("sq-bg11-14",ip,"scenario_responses","A patient asks to see their medical records.","How would you facilitate medical record access?","You have every right to see your records. I can help you access them through the patient portal, or you can request copies from medical records. Some records may need physician interpretation, but you are entitled to review all your information. Would you like me to help you get started with the portal?","Medical records access facilitation.","beginner"),
  q("sq-bg11-15",ip,"star_examples","Describe a time you showed empathy.","Share an empathy example from your clinical experience.","A patient was newly diagnosed with diabetes and overwhelmed by the lifestyle changes. Instead of launching into education, I sat down and asked what scared them most. They expressed fear about giving themselves injections. We started there—practicing with a saline injection together—and their confidence grew enough to absorb the rest of the education.","Patient-centered empathy before education.","beginner"),
  q("sq-bg11-16",ws,"prioritization","A patient needs a dressing change and another needs pre-operative teaching.","Which takes priority: dressing change or pre-op teaching?","If the dressing change is routine, pre-operative teaching takes priority because the patient will lose the opportunity if not done before the procedure. If the dressing is saturated or the wound shows signs of deterioration, the dressing change takes priority. Time-sensitivity and clinical urgency guide the decision.","Time-sensitive task prioritization.","beginner"),
  q("sq-bg11-17",ws,"prioritization","Three call lights are going off simultaneously.","How would you handle simultaneous call lights?","I would quickly assess each room while answering: peek in the nearest room to assess urgency, answer the next call light similarly, and prioritize based on what I find. I would delegate what I can and address the most clinically urgent need first. I would also assess whether staffing support is needed if this is a pattern.","Rapid assessment simultaneous call light management.","beginner"),
  q("sq-bg11-18",ws,"delegation","You need to delegate patient transport to a transporter.","How would you communicate safe transport needs?","I would provide: patient name, destination, mode of transport (wheelchair, stretcher), oxygen needs, IV pump requirements, isolation precautions, fall risk status, and any monitoring needs during transport. For high-risk patients, I would accompany or arrange nurse escort. Clear transport communication prevents delays and safety incidents.","Complete transport delegation communication.","beginner"),
  q("sq-bg11-19",ws,"delegation","A CNA reports a patient's blood pressure is 180/100.","How would you respond to a CNA reporting elevated BP?","I would assess the patient immediately—this could indicate hypertensive urgency. I would verify the reading myself, assess for symptoms of end-organ damage, check the patient's baseline and medication schedule, and notify the provider. I would thank the CNA for the prompt report and provide feedback on what to watch for.","CNA vital sign report response with verification.","beginner"),
  q("sq-bg11-20",ws,"patient_safety","A patient pulls out their nasogastric tube.","How would you manage NG tube removal by a patient?","I would assess the patient for complications (aspiration, nasal trauma), determine whether the NG tube needs replacement based on the clinical indication, notify the provider, and address the underlying reason for removal (discomfort, confusion). I would consider alternatives to NG tube if the patient repeatedly removes it and discuss with the team.","NG tube self-removal management.","beginner"),
  q("sq-bg11-21",ws,"patient_safety","A patient on a continuous infusion has swelling at the IV site.","What does swelling at an infusion site indicate?","Swelling at the IV site indicates infiltration—fluid is leaking into the surrounding tissue. I would stop the infusion immediately, remove the IV, assess the extent of swelling using a grading scale, apply warm or cold compress depending on the infused medication, elevate the extremity, restart the IV at a new site, and document the incident.","IV infiltration assessment and management.","beginner"),
  q("sq-bg11-22",ws,"medication_error","A patient receives a medication that was discontinued.","How would you manage administration of a discontinued medication?","I would assess the patient for adverse effects from the discontinued medication, notify the provider about the administration, investigate how the discontinued order was still available for administration, file a safety report, and ensure the medication is removed from all dispensing systems. System failures that allow discontinued medication administration need immediate correction.","Discontinued medication administration response.","intermediate"),
  q("sq-bg11-23",ws,"medication_error","A nurse asks you to waste a controlled substance with them but the amount seems wrong.","How would you handle a suspicious controlled substance waste?","I would not co-sign a waste that appears incorrect. I would verify the amount against the patient's order and the dispensed amount. If there is a discrepancy, I would report it to the charge nurse and pharmacy. Drug diversion is a serious safety issue, and co-signing inaccurate waste makes me complicit.","Controlled substance waste verification integrity.","intermediate"),
  q("sq-bg11-24",ws,"handoff_communication","A patient's status changes significantly just before shift change.","How would you communicate acute changes at shift change?","I would prioritize the acute change in my handoff: 'The most important thing you need to know is that Mr. Davis deteriorated in the last hour—BP dropped from 120 to 85, he became confused, and I started a fluid bolus. The physician is aware and ordered repeat labs at 1900. He needs close monitoring.'","Acute change-prioritized handoff.","beginner"),
  q("sq-bg11-25",ws,"difficult_coworkers","A colleague takes personal calls during patient care.","How would you address personal phone use during patient care?","If it directly affects patient care, I would address it: 'I understand personal calls can be important, but taking calls during medication passes creates safety risks. Could you take calls during your break instead?' If the behavior continues and affects patients, I would escalate with documented examples.","Patient care-focused phone use discussion.","beginner"),
  q("sq-bg11-26",ws,"interdisciplinary_communication","A respiratory therapist disagrees with your oxygen assessment.","How would you resolve an oxygen therapy disagreement?","I would discuss it collaboratively: 'I assessed the patient's SpO2 at 88% on room air and initiated 2L NC per standing order. What are you observing differently?' I would review the current orders together, consider the patient's baseline and target range, and involve the physician if we cannot reach consensus.","Collaborative oxygen management with RT.","beginner"),
  q("sq-bg11-27",ct,"first_shift","You are nervous about your first code blue.","How would you prepare for your first code blue?","I would review ACLS algorithms, know the location of the crash cart and defibrillator on my unit, practice with simulation, and discuss common code roles with experienced nurses. During my first real code, I would volunteer for a specific role (compressions, documentation, medication nurse) rather than standing frozen. Every code is a learning experience.","Code blue preparation with role selection.","beginner"),
  q("sq-bg11-28",ct,"new_nurse_anxiety","You feel like you ask too many questions.","Is asking too many questions a problem as a new nurse?","Asking questions is the safest behavior a new nurse can demonstrate. The danger is NOT asking when unsure. I would rather be known as the nurse who asks many questions than the one who made a preventable error. Over time, my questions will become more targeted as my knowledge base grows. Curiosity is a professional strength.","Questioning as professional safety behavior.","beginner"),
  q("sq-bg11-29",ct,"time_management","You are running behind on morning assessments.","How would you catch up on delayed assessments?","I would triage: perform abbreviated safety assessments on all patients first, then return for comprehensive assessments starting with the highest-acuity patients. I would communicate the delay to the charge nurse and delegate appropriate tasks. I would identify what caused the delay and adjust my future workflow to prevent the pattern.","Delayed assessment recovery strategy.","beginner"),
  q("sq-bg11-30",ct,"documentation_challenges","You witness a patient fall but the documentation system is down.","How would you document a fall during a system outage?","I would document on paper immediately using the facility's downtime forms, noting the exact time, circumstances, assessment findings, interventions, and provider notifications. When the system is restored, I would enter the documentation with the actual event times, noting it was entered during a system recovery. Timely documentation is critical regardless of system status.","System outage fall documentation.","beginner"),
  q("sq-bg11-31",ct,"critical_thinking_drills","A patient's serum potassium is 5.8 mEq/L.","How would you manage potassium of 5.8?","Potassium of 5.8 (normal 3.5-5.0) requires urgent action. I would place on cardiac monitoring, obtain a stat ECG checking for peaked T waves, hold all potassium-containing supplements and fluids, anticipate calcium gluconate for cardiac protection, insulin with dextrose for potassium shifting, and kayexalate. I would recheck potassium in 1-2 hours.","Hyperkalemia urgent management protocol.","intermediate"),
  q("sq-bg11-32",ct,"critical_thinking_drills","A patient's platelet count is 40,000.","What precautions does a platelet count of 40,000 require?","Platelets of 40,000 (normal 150,000-400,000) place the patient at significant bleeding risk. I would implement bleeding precautions: no IM injections, use soft toothbrush, apply pressure for 10+ minutes after venipuncture, avoid rectal procedures, check for petechiae and bruising, monitor for occult blood, and report any signs of bleeding. Transfusion may be needed below 10,000 or before procedures.","Thrombocytopenia bleeding precaution implementation.","intermediate"),
  q("sq-bg11-33",pd,"professional_boundaries","A patient asks for your home phone number.","How would you decline personal contact information requests?","I would redirect: 'I understand we have developed a good connection. However, I need to keep my personal contact information private as part of maintaining professional boundaries. If you need to reach the healthcare team after discharge, you can contact the unit directly at [number] or use the patient portal.'","Personal contact information boundary.","beginner"),
  q("sq-bg11-34",pd,"ethical_dilemmas","A family wants full resuscitation for a patient who previously expressed DNR wishes.","How would you handle family-patient DNR conflict?","I would review the patient's documented wishes, ensure the medical team is aware of the conflict, request an ethics consultation, and advocate for the patient's previously expressed autonomous decision. If the patient has a valid advance directive specifying DNR, that document should guide care. Family wishes do not override a competent patient's advance directive.","Advance directive supremacy over family wishes.","advanced"),
  q("sq-bg11-35",pd,"advocacy","A patient is being prescribed a medication they already told the doctor they cannot afford.","How would you advocate for affordable medication alternatives?","I would communicate to the provider: 'The patient has expressed that they cannot afford this medication. Can we explore generic alternatives, manufacturer assistance programs, or therapeutic substitutions? Medication non-adherence due to cost is a significant risk factor for readmission.' I would involve pharmacy and social work.","Affordable medication advocacy with alternative exploration.","beginner"),
  q("sq-bg11-36",pd,"patient_communication","A patient misunderstands their diagnosis and thinks they are dying.","How would you correct a patient's misunderstanding about their prognosis?","I would clarify gently: 'I want to make sure you have accurate information. What did the doctor tell you about your diagnosis?' I would correct specific misunderstandings within my scope, ensure the physician addresses the patient's concerns comprehensively, and provide emotional support. Medical misunderstandings cause unnecessary anxiety and can affect treatment compliance.","Gentle diagnosis misunderstanding correction.","beginner"),
  q("sq-bg11-37",pd,"workplace_bullying","A colleague makes inappropriate jokes about new graduates.","How would you address derogatory jokes about new nurses?","I would address it directly: 'Those jokes about new graduates are discouraging and create an unwelcoming environment. We were all new once, and negative comments do not help anyone develop into a better nurse.' If the behavior continued, I would document and report it as creating a hostile work environment.","New nurse joke confrontation.","beginner"),
  q("sq-bg11-38",cn,"job_offer_negotiation","You are asked about shift preference during an interview.","How would you discuss shift preference?","I would be honest but flexible: 'I understand that new graduates typically work night shifts, and I am prepared for that. I would eventually prefer to transition to day shift as opportunities arise, but I am committed to working whatever shift is needed to start. I am focused on building my clinical skills regardless of shift assignment.'","Flexible shift preference with honest aspiration.","beginner"),
  q("sq-bg11-39",cn,"probation_period","You receive inconsistent feedback from different preceptors.","How would you navigate inconsistent preceptor feedback?","I would seek clarification: 'I have received different feedback from my preceptors about this technique. Could we discuss the unit standard so I can be consistent?' I would not play preceptors against each other. I would reference facility policy as the objective standard and ask my manager for clarity on expectations.","Inconsistent feedback navigation with policy reference.","beginner"),
  q("sq-bg11-40",cn,"career_advancement","You want to understand different nursing certifications.","What nursing certifications are valuable for new graduates?","Initial certifications to pursue: BLS (required), ACLS (within 6 months), specialty certification relevant to your unit (Med-Surg CMSRN, pediatric CPN, critical care CCRN). Specialty certifications typically require 1-2 years of experience. Certifications demonstrate commitment to excellence and often come with salary increases.","New graduate certification roadmap.","beginner"),
  q("sq-bg11-41",ip,"clinical_judgment","A patient develops Clostridium difficile colitis.","How would you manage C. diff infection?","C. diff presents with watery diarrhea, abdominal cramping, and fever, often after antibiotic use. I would initiate contact precautions with bleach-based cleaning, administer oral vancomycin or fidaxomicin as ordered, discontinue the causative antibiotic if possible, monitor for complications (toxic megacolon, perforation), and track stool frequency.","C. diff management with contact precautions.","beginner"),
  q("sq-bg11-42",ip,"clinical_judgment","A patient develops acute coronary syndrome with ST elevation.","What is the door-to-balloon time target for STEMI?","The door-to-balloon time target for STEMI is less than 90 minutes. I would activate the cath lab immediately, administer aspirin and heparin, obtain IV access, perform a 12-lead ECG within 10 minutes, prepare the patient for emergent PCI, and coordinate with the cath lab team. Every minute of delay increases myocardial damage.","STEMI time-critical intervention.","intermediate"),
  q("sq-bg11-43",ip,"clinical_judgment","A patient develops cardiogenic pulmonary edema.","How would you manage acute cardiogenic pulmonary edema?","I would position upright, administer oxygen (BiPAP preferred for acute pulmonary edema), give IV furosemide for rapid diuresis, administer IV nitroglycerin if BP permits, morphine if ordered for preload reduction and anxiety, and prepare for possible intubation if non-invasive ventilation fails. I would monitor I&O closely and aim for negative fluid balance.","Acute cardiogenic pulmonary edema management.","intermediate"),
  q("sq-bg11-44",ws,"patient_safety","A patient on isolation precautions needs emergent CPR.","How do you balance PPE with emergent CPR?","For immediately life-threatening situations like cardiac arrest, I would don gloves and begin CPR without delay for full PPE. I would apply the defibrillator immediately. As additional responders arrive, they can don full PPE. Patient survival depends on immediate compressions and defibrillation—seconds of delay reduce survival.","Emergency CPR with minimal PPE delay.","intermediate"),
  q("sq-bg11-45",ws,"medication_error","A patient's insulin is scheduled but their meal tray has not arrived.","How would you handle insulin timing with a delayed meal?","I would hold rapid-acting insulin until the meal is available—administering insulin without food causes hypoglycemia. For long-acting insulin, I would administer as scheduled since it is not meal-dependent. I would contact dietary about the delayed tray and document the reason for the timing adjustment. Insulin-meal timing coordination is critical.","Insulin-meal timing coordination.","beginner"),
  q("sq-bg11-46",ct,"first_shift","You need to prepare for your first night shift.","How would you prepare for your first night shift?","I would adjust my sleep schedule gradually before the shift, prepare meals in advance, ensure a dark sleeping environment for daytime sleep, plan my workflow knowing that nights have different resource availability, identify the charge nurse and resources on the night shift, and accept that the first few nights will be an adjustment.","Night shift preparation strategy.","beginner"),
  q("sq-bg11-47",ct,"critical_thinking_drills","A patient's total bilirubin is 5.2 mg/dL.","What does elevated total bilirubin indicate?","Bilirubin of 5.2 (normal 0.1-1.2) causes clinical jaundice (visible above 2.5). Elevation can be direct (conjugated—liver/bile duct pathology), indirect (unconjugated—hemolysis, Gilbert's), or both. I would check direct versus indirect levels, assess for liver disease (check LFTs), hemolysis (check LDH, haptoglobin), and biliary obstruction (check ALP, imaging).","Bilirubin fractionation for cause identification.","intermediate"),
  q("sq-bg11-48",pd,"ethical_dilemmas","A competent patient makes sexual comments toward you.","How would you handle sexual harassment from a patient?","I would set a clear boundary: 'That comment is inappropriate and makes me uncomfortable. I am here to provide your medical care, and I need our interactions to remain professional. If this behavior continues, I will request a different nurse be assigned to your care.' I would document the incident and inform the charge nurse.","Patient sexual harassment boundary setting.","intermediate"),
  q("sq-bg11-49",cn,"career_advancement","You want to understand nurse practitioner practice authority.","What should you know about NP practice authority?","NP practice authority varies by state: full practice (independent prescribing and practice), reduced practice (collaborative agreement required), and restricted practice (supervisory agreement required). The trend is toward full practice authority. Understanding your state's regulations is essential for career planning as an advanced practice nurse.","NP practice authority landscape.","intermediate"),
  q("sq-bg11-50",ip,"clinical_judgment","A patient develops acute limb ischemia.","How would you recognize acute limb ischemia?","Acute limb ischemia presents with the 6 P's: Pain, Pallor, Pulselessness, Paresthesias, Paralysis, and Poikilothermia (cold). This is a vascular emergency requiring immediate intervention within 6 hours to prevent amputation. I would notify the vascular surgeon, anticoagulate with heparin, and prepare for emergent thrombectomy or thrombolysis.","Acute limb ischemia 6 P's recognition.","advanced"),
  q("sq-bg11-51",ip,"clinical_judgment","A patient with heart failure is started on an ACE inhibitor.","What monitoring is needed when starting ACE inhibitors?","I would monitor: blood pressure for hypotension (especially first dose), potassium for hyperkalemia, creatinine for renal function changes, and watch for angioedema symptoms. A small creatinine rise of up to 30% from baseline is expected and acceptable. I would educate about the dry cough side effect and when to seek emergency care for swelling.","ACE inhibitor initiation monitoring.","beginner"),
  q("sq-bg11-52",ws,"prioritization","You receive lab results showing a critical value while giving another patient a bath.","How would you handle a critical lab during a non-urgent task?","I would stop the bath safely, ensure the patient is comfortable and covered, and immediately address the critical lab result. Critical values require prompt provider notification—usually within 30 minutes. I would assess the affected patient, call the provider, implement any standing orders, and return to complete the bath afterward.","Critical value priority over non-urgent tasks.","beginner"),
  q("sq-bg11-53",ws,"delegation","You need a CNA to obtain a 12-lead ECG.","Can CNAs perform 12-lead ECGs?","ECG recording may be within CNA scope in some facilities with proper training and competency verification. I would verify the CNA's training status. If certified, I would ensure correct lead placement by demonstrating the first time. However, ECG interpretation is always the RN's or provider's responsibility. If the CNA is not trained, I would perform it myself.","ECG scope verification before delegation.","beginner"),
  q("sq-bg11-54",ct,"documentation_challenges","You need to document a patient's refusal of blood products for religious reasons.","How would you document a religious refusal of blood products?","I would document: 'Patient identifies as Jehovah's Witness and refuses all blood products including packed red blood cells, fresh frozen plasma, platelets, and cryoprecipitate. Patient has decision-making capacity as demonstrated by [specific assessment]. Risks of refusal including death were discussed thoroughly by physician at [time]. Patient verbalized understanding and maintains refusal. Signed refusal form on chart.'","Religious blood product refusal documentation.","intermediate"),
  q("sq-bg11-55",pd,"patient_communication","A patient does not understand medical jargon.","How would you translate medical terminology for patients?","I would replace jargon with plain language: 'edema' becomes 'swelling,' 'dyspnea' becomes 'trouble breathing,' 'NPO' becomes 'nothing to eat or drink.' I would check understanding frequently: 'Does that make sense? Do you have any questions?' I would avoid using medical terminology unless the patient shows they understand it.","Medical jargon plain language translation.","beginner"),
  q("sq-bg11-56",cn,"performance_evaluation","You want to demonstrate growth in clinical reasoning.","How would you show clinical reasoning improvement during evaluation?","I would present specific examples: 'When I started, I focused on isolated findings. Now I synthesize: when Mrs. Garcia's BP dropped, I immediately considered her new medications, morning lab results, and overnight fluid balance to form a differential before calling the physician. My clinical thinking has evolved from reactive to anticipatory.'","Clinical reasoning growth evidence.","beginner"),
  q("sq-bg11-57",ip,"clinical_judgment","A patient develops acute angle-closure glaucoma symptoms.","What medications can trigger acute glaucoma?","Anticholinergic medications can trigger acute angle-closure glaucoma in predisposed patients by causing pupil dilation. Common triggers include atropine, antihistamines, scopolamine, and some antidepressants. Before administering anticholinergic medications, I would check for glaucoma history. Symptoms include sudden eye pain, headache, nausea, and visual halos.","Anticholinergic glaucoma trigger awareness.","intermediate"),
  q("sq-bg11-58",ws,"patient_safety","A patient's arterial line becomes disconnected.","How would you manage an arterial line disconnection?","I would apply direct pressure to the site immediately—arterial lines can cause rapid blood loss and air embolism. I would assess the patient's hemodynamic status, reconnect the system using sterile technique, check waveform quality, compare blood pressure with a cuff reading, and document the event. Prevention includes securing all connections.","Arterial line disconnection emergency response.","intermediate"),
  q("sq-bg11-59",ct,"time_management","You need to manage care for a patient requiring 1:1 monitoring.","How would you manage other patients while providing 1:1 care?","I would communicate the staffing need to the charge nurse immediately—1:1 monitoring means I cannot safely leave this patient for extended periods. I would request assignment redistribution or a sitter. If I must manage other patients temporarily, I would prioritize their most critical needs and delegate non-essential tasks.","1:1 monitoring workload communication.","intermediate"),
  q("sq-bg11-60",pd,"advocacy","A patient is being discharged with a condition that requires home health but none was ordered.","How would you initiate home health referral?","I would assess the patient's post-discharge needs, document my assessment findings supporting home health necessity, communicate the need to the physician and case manager, initiate the referral process, and ensure the patient understands what services they will receive. Home health can prevent readmission and improve outcomes.","Proactive home health referral initiation.","beginner"),
  q("sq-bg11-61",ip,"clinical_judgment","A patient with COPD is on 6L oxygen via nasal cannula.","Why is high-flow oxygen concerning in COPD patients?","Some COPD patients rely on hypoxic drive for ventilatory stimulus. High-flow oxygen can suppress this drive, causing CO2 retention and respiratory failure. I would target SpO2 88-92% for COPD patients, monitor for signs of CO2 narcosis (confusion, lethargy), and check ABGs if oxygen requirements increase. Not all COPD patients have hypoxic drive dependency.","COPD oxygen therapy with hypoxic drive consideration.","intermediate"),
  q("sq-bg11-62",ws,"handoff_communication","You are giving report on a patient with a complex wound care plan.","How would you ensure wound care plan continuity?","I would provide: wound location and size with last measurement date, current treatment orders, last dressing change date and findings, wound healing trajectory (improving/worsening/static), any planned changes in treatment, supplies needed for next change, and patient's pain management during wound care. Wound care handoff should enable trend assessment.","Wound care plan handoff with trending.","beginner"),
  q("sq-bg11-63",ct,"critical_thinking_drills","A patient's calcium is 7.0 mg/dL.","What does severe hypocalcemia cause?","Calcium of 7.0 (normal 8.5-10.5) can cause life-threatening complications: tetany, laryngospasm, seizures, and cardiac arrhythmias (prolonged QT). I would check for Chvostek's and Trousseau's signs, place on cardiac monitoring, administer IV calcium gluconate slowly, check magnesium (needed for calcium absorption), and identify the cause.","Severe hypocalcemia emergency management.","intermediate"),
  q("sq-bg11-64",pd,"professional_boundaries","You see a patient at the grocery store.","How would you handle encountering a patient in public?","I would not initiate contact—the patient may not want to be identified as a patient in public. If the patient approaches me, I would be warm but brief and would not discuss any medical information in public. I would not acknowledge knowing them as a patient to anyone I am with. Patient privacy extends beyond the hospital.","Public patient encounter privacy.","beginner"),
  q("sq-bg11-65",cn,"career_advancement","You want to understand travel nursing requirements.","What are the prerequisites for travel nursing?","Most travel agencies require: minimum 1-2 years of clinical experience in your specialty, active nursing license (compact license preferred), BLS/ACLS certifications, ability to adapt quickly to new environments, and strong independent clinical skills. Travel nursing offers higher pay but less job security and requires self-sufficiency. Compact nursing licensure facilitates multi-state practice.","Travel nursing prerequisite overview.","beginner"),
  q("sq-bg11-66",ip,"clinical_judgment","A patient develops subclavian steal syndrome.","What is subclavian steal syndrome?","Subclavian steal occurs when subclavian artery stenosis proximal to the vertebral artery origin causes reversed vertebral artery flow, stealing blood from the posterior cerebral circulation. Symptoms include arm claudication with dizziness, visual changes, or syncope during arm exercise. I would check bilateral arm blood pressures for a >20 mmHg difference and notify the vascular team.","Subclavian steal recognition with bilateral BP comparison.","advanced"),
  q("sq-bg11-67",ws,"medication_error","A patient receives an IM injection in the wrong site.","What are the consequences of IM injection in the wrong site?","Wrong-site IM injections can cause sciatic nerve damage (if given too medially in the dorsogluteal area), subcutaneous injection (if the needle is too short for the site), or inadequate absorption. I would assess the patient for nerve injury symptoms, document the actual injection site, and use the ventrogluteal site as the preferred IM location.","IM injection site safety with ventrogluteal preference.","beginner"),
  q("sq-bg11-68",ct,"new_nurse_anxiety","You worry about making a mistake that hurts a patient.","How do you manage the fear of causing patient harm?","I would channel the fear into diligence: follow safety protocols religiously, verify everything, ask questions, and never take shortcuts. I would recognize that multiple safety systems protect patients—I am one important layer but not the only one. I would also understand that perfection is not possible, but consistent competent practice minimizes harm.","Constructive fear channeling into safety practice.","beginner"),
  q("sq-bg11-69",pd,"ethical_dilemmas","A patient with a terminal illness wants to stop treatment but their family disagrees.","How would you support a patient choosing to stop treatment against family wishes?","I would ensure the patient has decision-making capacity, document their wishes clearly, facilitate a family meeting with the physician and palliative care team, support the patient's autonomous decision, and provide emotional support to both the patient and family. The patient's wishes take precedence when they have capacity, even when the family disagrees.","Patient autonomy support in treatment cessation.","advanced"),
  q("sq-bg11-70",cn,"probation_period","Your preceptor is supportive but not teaching you advanced skills.","How would you request advanced learning opportunities?","I would express my readiness: 'I feel confident with my current skills and would like to learn more advanced techniques. Could we plan some opportunities for me to practice [specific skills] with your supervision? I want to continue growing during the remaining orientation time.' Proactive learning requests show initiative.","Advanced skill learning request.","beginner"),
  q("sq-bg11-71",ip,"clinical_judgment","A patient on antipsychotics develops akathisia.","How would you recognize and manage akathisia?","Akathisia is an extrapyramidal side effect of antipsychotics characterized by restlessness, an inability to sit still, and inner tension. It is often mistaken for anxiety or agitation. I would assess for medication timing correlation, notify the prescriber, and anticipate treatment with propranolol or benztropine. Increasing the antipsychotic dose for perceived agitation would worsen akathisia.","Akathisia recognition versus misidentified agitation.","intermediate"),
  q("sq-bg11-72",ws,"patient_safety","A patient develops acute transfusion reaction with hives.","How would you manage mild transfusion reaction?","For mild allergic reaction (hives only, no systemic symptoms), I would stop the transfusion, assess vital signs, administer diphenhydramine as ordered, and notify the provider. If symptoms resolve, the transfusion may be restarted slowly per physician order. For any systemic symptoms (dyspnea, hypotension, fever), I would stop the transfusion permanently.","Mild versus severe transfusion reaction differentiation.","beginner"),
  q("sq-bg11-73",ct,"documentation_challenges","You need to document end-of-life care.","What should end-of-life documentation include?","I would document: comfort measures provided, symptom management (pain, dyspnea, anxiety), family presence and emotional support given, code status verification, spiritual care provided, patient's level of consciousness, advance directive compliance, time of death if applicable, and any final wishes honored. End-of-life documentation should reflect compassionate, dignified care.","Compassionate end-of-life documentation.","intermediate"),
  q("sq-bg11-74",pd,"patient_communication","A patient asks you about side effects they read online.","How would you address medication concerns from internet research?","I would validate their research while ensuring accuracy: 'I am glad you are taking an active role in understanding your medications. Let me review what you found and help separate common, expected effects from rare concerns. Some online sources can be misleading, so let us look at the most reliable information together.'","Internet research validation with clinical guidance.","beginner"),
  q("sq-bg11-75",cn,"career_advancement","You are interested in becoming a charge nurse.","What skills does a charge nurse need?","Charge nurses need: strong clinical skills to support staff decisions, conflict resolution abilities, prioritization under pressure, delegation skills, effective communication with administration and physicians, staffing management knowledge, and the ability to lead without controlling. I would develop these skills through progressive leadership roles.","Charge nurse skill requirements.","intermediate"),
  q("sq-bg11-76",ip,"clinical_judgment","A patient develops acute cholecystitis.","How would you recognize acute cholecystitis?","Acute cholecystitis presents with right upper quadrant pain (Murphy's sign positive), fever, nausea, and leukocytosis. I would keep the patient NPO, administer IV antibiotics, provide pain management, and prepare for possible cholecystectomy. Ultrasound typically shows gallbladder wall thickening and pericholecystic fluid. I would monitor for complications including perforation and empyema.","Acute cholecystitis recognition and management.","intermediate"),
  q("sq-bg11-77",ws,"delegation","You need a CNA to perform oral care on an intubated patient.","Can CNAs perform oral care on intubated patients?","Oral care for intubated patients requires specific training. I would verify the CNA's competency for intubated patient care, demonstrate the technique if needed, specify: use chlorhexidine solution per protocol, suction the oral cavity, do not disconnect or adjust the ETT or ventilator settings, and report any ETT displacement immediately.","Intubated patient oral care delegation with ETT precautions.","intermediate"),
  q("sq-bg11-78",ct,"critical_thinking_drills","A patient's TSH is 0.1 with elevated free T4.","What does suppressed TSH with elevated T4 indicate?","Suppressed TSH of 0.1 (normal 0.4-4.0) with elevated free T4 indicates hyperthyroidism. The thyroid is producing excessive hormone and the pituitary has suppressed TSH in response. Symptoms include tachycardia, weight loss, heat intolerance, tremor, and anxiety. I would anticipate antithyroid medication or radioactive iodine treatment and monitor for thyroid storm risk.","Hyperthyroidism lab pattern recognition.","beginner"),
  q("sq-bg11-79",pd,"advocacy","A patient needs interpreter services but the family insists on translating.","Why should professional interpreters be used instead of family?","Family members should not serve as medical interpreters because they may omit uncomfortable information, misunderstand medical terminology, have their own emotional reactions that affect translation accuracy, and create HIPAA concerns. I would explain: 'A professional interpreter ensures complete, accurate communication. Your family can be present for support, but we need a trained interpreter for medical discussions.'","Family translation refusal with professional interpreter advocacy.","beginner"),
  q("sq-bg11-80",cn,"performance_evaluation","You want to establish a mentoring relationship with a leader.","How would you approach a potential mentor?","I would identify a leader whose career path aligns with my aspirations, observe their approach to challenges, and request a meeting: 'I admire how you manage [specific strength]. I am looking for guidance as I develop my nursing career. Would you be open to occasional conversations about professional development?' Specific, genuine requests are most effective.","Targeted mentor approach with specific admiration.","beginner"),
  q("sq-bg11-81",ip,"clinical_judgment","A patient develops peritoneal dialysis-related peritonitis.","How would you recognize PD peritonitis?","PD peritonitis presents with cloudy dialysate, abdominal pain, and fever. I would collect a dialysate sample for cell count and culture before starting antibiotics, administer intraperitoneal antibiotics per protocol, monitor drain effluent clarity, and assess for catheter tunnel infection. PD peritonitis can lead to catheter loss if not treated promptly.","PD peritonitis recognition with sample collection.","intermediate"),
  q("sq-bg11-82",ws,"interdisciplinary_communication","A patient's pain is poorly managed despite multiple interventions.","How would you escalate persistent pain management failure?","I would document the pattern: 'Despite [interventions tried], pain remains at 8/10. Current regimen is not adequately controlling this patient's pain.' I would request a pain management consultation, present objective data on medication effectiveness, advocate for multimodal approaches, and ensure the patient knows I am working to improve their comfort.","Pain management escalation with multimodal advocacy.","intermediate"),
  q("sq-bg11-83",ct,"time_management","You are juggling patient education with urgent tasks.","How would you balance education with clinical urgency?","I would prioritize: urgent clinical tasks first, then education during naturally occurring pauses (waiting for medications, between procedures). I would identify key teachable moments during care activities—combining medication administration with medication education saves time while enhancing learning. I would not sacrifice education entirely but would adapt delivery.","Integrated education during care activities.","beginner"),
  q("sq-bg11-84",pd,"workplace_bullying","A colleague mocks your nursing school education.","How would you respond to education-based mockery?","I would address it factually: 'I am proud of my nursing education. Every nurse's path is different, and what matters most is the care we provide our patients. I would appreciate mutual respect for each other's backgrounds so we can focus on what we have in common—excellent patient care.' I would not engage in a comparison debate.","Education mockery response with focus redirection.","beginner"),
  q("sq-bg11-85",cn,"job_offer_negotiation","You are negotiating for a specific unit or department.","How would you negotiate for a preferred unit placement?","I would express my interest with clinical rationale: 'I am specifically interested in the cardiac step-down unit because my clinical experience in cardiac care was where I felt most engaged and performed my best. My ACLS certification and cardiac clinical rotation prepare me well for this unit. Is there flexibility in the placement decision?'","Clinical rationale for unit preference.","beginner"),
  q("sq-bg11-86",ip,"clinical_judgment","A patient develops anemia from chronic kidney disease.","How is CKD-related anemia managed?","CKD-related anemia results from decreased erythropoietin production by failing kidneys. Treatment includes erythropoietin-stimulating agents (epoetin alfa, darbepoetin), iron supplementation if stores are low, and transfusion for severe symptomatic anemia. I would monitor hemoglobin targets (usually 10-11.5), iron studies, and watch for ESA-related hypertension.","CKD anemia with ESA monitoring.","intermediate"),
  q("sq-bg11-87",ws,"patient_safety","A patient on warfarin needs a dental procedure.","How would you prepare for dental procedures on anticoagulated patients?","I would coordinate with the dentist and physician regarding INR target for the procedure, determine if warfarin needs to be held or bridged with heparin, check INR before the procedure, ensure the patient knows their current anticoagulation status, and plan for post-procedure bleeding management. Most minor dental procedures can be done with INR 2.0-3.0.","Anticoagulated patient dental procedure coordination.","intermediate"),
  q("sq-bg11-88",ct,"documentation_challenges","You need to document the administration of a high-alert medication.","What extra documentation do high-alert medications require?","I would document: independent double-check verification by a second nurse, the second nurse's name and credentials, patient identification verification, dosage calculation if applicable, pump settings verification, patient assessment before and after administration, and any monitoring parameters. High-alert medications require additional documentation because errors with these drugs have the highest potential for harm.","High-alert medication enhanced documentation.","intermediate"),
  q("sq-bg11-89",pd,"ethical_dilemmas","A colleague uses a patient's story in a presentation without consent.","How would you address unauthorized use of patient information?","I would notify the colleague: 'Using a patient's identifiable information in a presentation without consent violates HIPAA and patient trust. The presentation needs to be modified to remove identifying details, or the patient needs to provide written consent. I would recommend discussing this with our privacy officer to ensure compliance.'","Patient information presentation privacy advocacy.","intermediate"),
  q("sq-bg11-90",cn,"career_advancement","You want to understand the difference between MSN and DNP.","How does MSN compare to DNP for career planning?","MSN prepares for advanced practice, education, or administration roles and is the minimum for most NP programs. DNP is a clinical doctorate focusing on evidence-based practice, leadership, and systems improvement. DNP is increasingly preferred for NP preparation and may become required. The choice depends on career goals, timeline, and whether you want to pursue research (PhD) versus practice improvement (DNP).","MSN versus DNP program comparison.","intermediate"),
  q("sq-bg11-91",ip,"clinical_judgment","A patient develops acute meningitis.","How would you recognize and manage acute bacterial meningitis?","Bacterial meningitis presents with headache, fever, nuchal rigidity, photophobia, and altered consciousness. Kernig's and Brudzinski's signs may be positive. Treatment is emergent: blood cultures and LP before antibiotics only if imaging is not needed, otherwise antibiotics should NOT be delayed for LP. I would administer dexamethasone before or with the first antibiotic dose. Droplet precautions until meningococcal meningitis is ruled out.","Meningitis emergency with antibiotics-first approach.","advanced"),
  q("sq-bg11-92",ws,"difficult_coworkers","A colleague keeps giving you unsolicited advice.","How would you handle persistent unsolicited advice?","I would respond graciously but set a boundary: 'I appreciate your experience and I value your input when I ask for it. I am working on developing my own clinical judgment and problem-solving skills. If I need help, I promise I will ask.' Unsolicited advice, while well-intentioned, can undermine confidence and prevent independent clinical growth.","Unsolicited advice boundary with gratitude.","beginner"),
  q("sq-bg11-93",ct,"first_shift","You are assigned a patient with a condition you studied but never saw clinically.","How would you approach an unfamiliar clinical condition?","I would review the condition quickly using clinical references, ask my preceptor for guidance on key monitoring parameters, perform a thorough assessment, compare my findings to expected presentation, and seek clarification for anything unexpected. I would not pretend to know more than I do—asking informed questions demonstrates clinical maturity.","Unfamiliar condition preparation with honest inquiry.","beginner"),
  q("sq-bg11-94",pd,"patient_communication","A patient repeatedly asks the same questions.","How would you manage a patient who repeats questions?","I would assess for cognitive changes that might explain the repetition, respond patiently each time, consider whether my initial explanations were unclear, provide written information they can reference, and determine if anxiety is driving the repeated questions. Repetitive questioning may indicate a medical issue requiring assessment rather than just poor memory.","Repetitive questioning assessment for underlying cause.","beginner"),
  q("sq-bg11-95",cn,"probation_period","You are asked to evaluate your own performance during probation.","How would you conduct an honest self-evaluation?","I would use specific examples: 'My clinical assessment skills have improved from requiring constant preceptor guidance to performing independently with appropriate escalation. Areas for continued growth include IV insertion confidence and complex wound care. My documentation speed has doubled while maintaining accuracy. I am committed to continuing this trajectory.'","Evidence-based self-evaluation with growth areas.","beginner"),
  q("sq-bg11-96",ip,"clinical_judgment","A patient develops posterior circulation stroke symptoms.","How do posterior circulation strokes present?","Posterior circulation strokes affect the brainstem and cerebellum, presenting with: vertigo, diplopia, dysarthria, dysphagia, ataxia, and crossed sensory/motor findings. Unlike anterior strokes, they may present with dizziness rather than obvious weakness. The NIHSS may underestimate severity. I would ensure rapid imaging (MRI is superior to CT for posterior fossa) and thrombolytic evaluation.","Posterior stroke recognition with NIHSS limitation.","advanced"),
  q("sq-bg11-97",ws,"patient_safety","A patient with a tracheostomy needs suctioning.","What is the correct tracheostomy suctioning technique?","I would use sterile technique, preoxygenate with 100% O2, insert the catheter without suction to the appropriate depth (no further than 1 cm beyond the tracheostomy tube tip), apply intermittent suction while withdrawing with a rotating motion, limit each pass to 10-15 seconds, allow recovery breaths between passes, and monitor SpO2 and heart rate throughout.","Sterile tracheostomy suctioning protocol.","beginner"),
  q("sq-bg11-98",ct,"critical_thinking_drills","A patient's chloride is 115 mEq/L.","What does hyperchloremia indicate?","Chloride of 115 (normal 96-106) with a normal anion gap suggests hyperchloremic metabolic acidosis. Common causes include: excessive normal saline administration, diarrhea with bicarbonate loss, and renal tubular acidosis. I would check the anion gap, review IV fluid orders (NS contains 154 mEq/L chloride), and consider switching to balanced crystalloids if NS is contributing.","Hyperchloremia from NS overuse awareness.","intermediate"),
  q("sq-bg11-99",pd,"advocacy","A patient needs a medication adjustment but the physician has not rounded.","How would you expedite a needed medication change?","I would call the physician directly with an SBAR communication: 'Mrs. Chen's blood pressure has been consistently above 170 systolic despite her current antihypertensive regimen for the past 12 hours. I am requesting consideration for a medication adjustment.' I would not wait indefinitely for rounding when a patient's condition warrants attention.","Proactive medication adjustment advocacy.","beginner"),
  q("sq-bg11-100",cn,"career_advancement","You are interested in military nursing.","What does military nursing involve?","Military nursing offers unique opportunities: disaster response, combat casualty care, global health, and leadership development. Requirements include BSN, active nursing license, physical fitness standards, and officer candidacy. Benefits include education assistance, travel, and rapid career advancement. Military nurses serve in hospitals, field units, and humanitarian missions worldwide.","Military nursing career overview.","beginner"),
  q("sq-bg11-101",ip,"clinical_judgment","A patient develops acute pancreatitis from hypertriglyceridemia.","How is hypertriglyceridemia-induced pancreatitis managed?","Triglycerides above 1000 mg/dL can cause acute pancreatitis. Treatment includes insulin infusion to activate lipoprotein lipase and lower triglycerides, heparin infusion in some protocols, NPO status, aggressive IV hydration, and pain management. I would monitor triglyceride levels every 12-24 hours and ensure a lipid-lowering regimen is started before discharge.","Hypertriglyceridemia pancreatitis specific management.","advanced"),
  q("sq-bg11-102",ws,"medication_error","A patient's medication reconciliation at admission missed a critical daily medication.","How could a missed medication during reconciliation harm a patient?","Missed medications during reconciliation can cause withdrawal (beta-blockers, SSRIs, benzodiazepines), disease exacerbation (antihypertensives, anticonvulsants), or dangerous rebound effects. I would complete medication reconciliation thoroughly using multiple sources (patient report, pharmacy records, prior hospitalization records) and verify the list with the patient and family.","Medication reconciliation completeness importance.","beginner"),
  q("sq-bg11-103",ct,"documentation_challenges","You need to document a patient's informed refusal of a procedure.","What must informed refusal documentation include?","I would document: specific procedure refused, patient's understanding of the procedure's purpose, specific risks of refusal explained by the physician, patient's stated reason for refusal, capacity assessment, alternatives discussed, physician notification, and patient's ongoing plan of care. The patient should sign a refusal form—if they decline to sign, I would document that as well.","Comprehensive informed refusal documentation.","beginner"),
  q("sq-bg11-104",pd,"patient_communication","A patient is anxious about a new medication.","How would you address medication anxiety?","I would explore the specific concern: 'What worries you about this medication?' I would provide accurate information about expected effects versus rare side effects, explain why the medication was prescribed, describe what monitoring we will do, and reassure them that their care team is watching for any problems. Informed patients are less anxious patients.","Targeted medication anxiety reduction.","beginner"),
  q("sq-bg11-105",cn,"career_advancement","You are considering nurse midwifery.","What does a nurse midwife career involve?","Certified nurse midwives provide comprehensive women's health care including prenatal, labor and delivery, postpartum, and well-woman care. Requirements include MSN or DNP with midwifery specialization and AMCB certification. CNMs can practice independently in most states. The profession offers high satisfaction, autonomy, and the privilege of supporting families during life-changing moments.","Nurse midwifery career overview.","intermediate"),
  q("sq-bg11-106",ip,"clinical_judgment","A patient develops tumor lysis syndrome prevention.","How would you prevent TLS in high-risk patients?","For high-risk patients starting chemotherapy, I would ensure aggressive IV hydration (2-3 L/m2/day), administer allopurinol or rasburicase prophylactically, monitor electrolytes and renal function every 6-8 hours, maintain urine output above 2 mL/kg/hr, and avoid potassium and phosphorus supplementation. Prevention is more effective than treatment for TLS.","TLS prophylaxis protocol.","intermediate"),
  q("sq-bg11-107",ws,"interdisciplinary_communication","A physical therapist reports a patient is unsafe for independent ambulation.","How would you respond to a PT safety recommendation?","I would update the fall risk assessment, change the activity order per PT recommendation, communicate the change to all nursing staff, update the care plan, place the patient on appropriate fall precautions, and educate the patient about their activity restrictions. PT recommendations about patient safety should be implemented promptly and communicated widely.","PT safety recommendation implementation.","beginner"),
  q("sq-bg11-108",ct,"new_nurse_anxiety","You feel overwhelmed by the emotional demands of nursing.","How would you develop emotional resilience?","I would develop regular self-care practices (exercise, sleep, social connections), seek professional support through EAP when needed, practice mindfulness or relaxation techniques, maintain boundaries between work and home, debrief after difficult experiences, and remember that emotional sensitivity is what makes me a compassionate nurse—it needs to be managed, not eliminated.","Emotional resilience development plan.","beginner"),
  q("sq-bg11-109",pd,"ethical_dilemmas","A patient asks you to pray for a specific outcome.","How would you respond to prayers for specific medical outcomes?","I would respond respectfully: 'I would be honored to hold positive thoughts for you. I can not promise specific outcomes, but I can promise that your care team is doing everything possible. Would you like me to arrange a chaplain visit for additional spiritual support?' I would support the patient's spiritual needs without making promises about medical outcomes.","Spiritual support without medical promises.","beginner"),
  q("sq-bg11-110",cn,"career_advancement","You want to learn about nurse anesthesia.","What does a CRNA career involve?","CRNAs administer anesthesia for surgeries and procedures, provide pain management, and manage post-anesthesia recovery. Requirements include BSN, minimum 1-2 years of critical care experience, completion of a DNP CRNA program (36-42 months), and national certification. CRNAs are among the highest-paid nursing specialties with significant clinical autonomy.","CRNA career requirements and overview.","intermediate"),
  q("sq-bg11-111",ip,"clinical_judgment","A patient develops aspiration pneumonia.","How would you manage aspiration pneumonia?","Aspiration pneumonia develops when gastric contents or oral secretions enter the lungs. I would initiate antibiotics targeting anaerobes and gram-negative organisms, elevate the head of bed, implement aspiration precautions, order a swallowing evaluation, provide oral care, and monitor respiratory status. Prevention through positioning, aspiration risk screening, and oral hygiene is more effective than treatment.","Aspiration pneumonia management with prevention focus.","intermediate"),
  q("sq-bg11-112",ws,"patient_safety","A patient's PICC line develops a suspected clot.","How would you manage a suspected PICC line occlusion?","I would not force-flush the line—this could dislodge a clot. I would attempt gentle aspiration, notify the provider, and anticipate an alteplase (cathflo) instillation order for thrombotic occlusion. I would check for mechanical obstruction (kink, clamp) first. If the line cannot be cleared, it may need replacement. I would document flushing difficulty and interventions.","PICC occlusion management without force-flushing.","intermediate"),
  q("sq-bg11-113",ct,"critical_thinking_drills","A patient's sodium is 152 mEq/L.","What does hypernatremia indicate?","Sodium of 152 (normal 135-145) indicates water deficit relative to sodium. Common causes include dehydration, diabetes insipidus, excessive sodium intake, and inadequate water access (elderly, intubated patients). I would assess hydration status, calculate free water deficit, provide appropriate fluid replacement, monitor sodium correction rate (no more than 10-12 mEq/L per day), and address the underlying cause.","Hypernatremia free water deficit management.","intermediate"),
  q("sq-bg11-114",pd,"professional_boundaries","A patient develops a romantic interest in you.","How would you manage patient romantic interest?","I would set a clear, kind boundary: 'I appreciate the connection we have, and I care about your wellbeing. However, our relationship must remain professional—it is a boundary that protects us both and ensures you receive objective, quality care. I want to continue providing the best care for you.' If the behavior escalated, I would involve the charge nurse.","Romantic interest professional boundary.","intermediate"),
  q("sq-bg11-115",cn,"performance_evaluation","You want to demonstrate your value beyond basic competency.","How would you show value-added contributions during evaluation?","I would present: improvements I suggested or implemented, patient compliments I received, safety catches I made, mentoring I provided, evidence-based practice changes I championed, and quality outcomes I contributed to. Value-added nurses are not just competent—they actively improve the care environment for patients and colleagues.","Value-added contribution evidence.","beginner"),
  q("sq-bg11-116",ip,"clinical_judgment","A patient develops status epilepticus.","How would you manage status epilepticus?","Status epilepticus (seizure >5 minutes or repeated seizures without recovery) is a neurological emergency. I would ensure airway safety, administer benzodiazepines (lorazepam 4mg IV or midazolam IM), prepare for repeat dosing, anticipate levetiracetam or fosphenytoin loading, call for help, and prepare for intubation if seizures continue despite medication. Time the seizure duration.","Status epilepticus escalating medication protocol.","advanced"),
  q("sq-bg11-117",ws,"handoff_communication","A patient was recently told bad news before your handoff.","How would you communicate emotional context during handoff?","I would include emotional assessment: 'Mrs. Thompson was told her biopsy is malignant at 1400. She has been crying and processing with her husband. She has asked to delay further discussions until tomorrow. The social worker and chaplain have both visited. She may need extra emotional support tonight. Her daughter plans to visit at 2000.'","Emotional context in clinical handoff.","beginner"),
  q("sq-bg11-118",ct,"time_management","You need to coordinate care with multiple ancillary services.","How would you coordinate multiple ancillary service visits?","I would create a timeline: schedule services in logical order (NPO patient gets blood work before meals, PT after pain medication peaks), communicate the schedule to the patient and each service, stagger visits to allow patient rest, and ensure nursing assessments and medications do not conflict with service appointments.","Ancillary service coordination scheduling.","beginner"),
  q("sq-bg11-119",pd,"advocacy","A patient's living conditions are contributing to their health problems.","How would you address social determinants of health?","I would screen for SDOH using validated tools, document housing, food security, and transportation barriers, involve social work, connect the patient with community resources, and advocate for addressing root causes alongside treating medical conditions. Healthcare that ignores social determinants often fails because patients return to the same environments that caused their illness.","SDOH screening and community resource connection.","intermediate"),
  q("sq-bg11-120",cn,"career_advancement","You are considering international nursing.","What opportunities exist for international nursing?","International nursing opportunities include: WHO and NGO health programs, military nursing overseas, travel nursing in countries with reciprocal agreements, nursing education in developing countries, and disaster relief nursing. Requirements vary by country but typically include experience, language skills, and credential verification. International experience broadens clinical perspective significantly.","International nursing opportunity overview.","beginner"),
];
